#!/usr/bin/env bash
# service.sh — Service 决策助手 for 软件架构 (含 应用架构 / 系统架构 / 分布式 后端架构 / 前后端 数据流 与 数据模型 设计 / API 边界 / 可扩展性 / 演进式架构 — 不含 硬件架构 / 纯企业架构 / 纯 DevOps / 纯安全架构).
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="软件架构 (含 应用架构 / 系统架构 / 分布式 后端架构 / 前后端 数据流 与 数据模型 设计 / API 边界 / 可扩展性 / 演进式架构 — 不含 硬件架构 / 纯企业架构 / 纯 DevOps / 纯安全架构)"
TOPIC="Service"

usage() {
  cat <<EOF
service.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 3 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./service.sh             # interactive
  ./service.sh --dry-run   # walk through but no file
  ./service.sh --json      # JSON to stdout
  ./service.sh --explain   # show backing playbook rules + mental models
  ./service.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 Service 主题下的 playbook 规则组合成交互树。

基于 3 条规则:
  • 如果 团队 < 10 人 + 服务 < 5 个 → 则 : modular monolith first, 不上 K8s / Kafka / service mesh; Pos
  • 如果 一致性要求 = "strong" 跨多 service → 则 : 默认单 service 内 transactions; 跨 service 用 Saga + outbox + 幂等
  • 如果 监控只有 metrics → 则 : 加 traces (OpenTelemetry 标准) + structured logs + sampling; 

相关心智模型:
  • 耦合 (coupling) 是唯一的硬通货 — 其它都是衍生: 软件架构本质 = 管理跨"独立变化速率"事物之间的依赖. Parnas 1972 "On the Criteria" 已说清: 模块边界要按"未来变化的轴"划, 不是按"功能流程"划. Fowler 
  • 架构 = 你早期希望做对、晚期改不动的那些决定 (the stuff that's hard to change later): Fowler 1999 给"architecture" 的工作定义: *architecture is about the important stuff, whatever that is — th

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "团队 < 10 人 + 服务 < 5 个"
  "一致性要求 = \"strong\" 跨多 service"
  "监控只有 metrics"
)
declare -a RULE_ACTIONS=(
  ": modular monolith first, 不上 K8s / Kafka / service mesh; PostgreSQL + Redis + 1 cloud (Fly.io / Render / Heroku / 阿里 ECS) 即可"
  ": 默认单 service 内 transactions; 跨 service 用 Saga + outbox + 幂等 receiver; 不要做 2PC / XA"
  ": 加 traces (OpenTelemetry 标准) + structured logs + sampling; 三柱齐才能定位 cross-service 问题"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "service-decision"
fi
